def gen(rng, size):
    n = rng.randint(1, max(1, size))
    vals = rng.sample(range(0, 10001), n)
    order = vals[:]
    rng.shuffle(order)
    root = None
    nodes = {}
    def insert(v):
        nonlocal root
        if root is None:
            root = v; nodes[v] = [None, None]; return
        cur = root
        while True:
            l, r = nodes[cur]
            if v < cur:
                if l is None:
                    nodes[cur][0] = v; nodes[v] = [None, None]; return
                cur = l
            else:
                if r is None:
                    nodes[cur][1] = v; nodes[v] = [None, None]; return
                cur = r
    for v in order:
        insert(v)
    out = []
    from collections import deque
    q = deque([root])
    while q:
        cur = q.popleft()
        if cur is None:
            out.append(None); continue
        out.append(cur)
        cl, cr = nodes[cur]
        q.append(cl); q.append(cr)
    while out and out[-1] is None:
        out.pop()
    a = rng.randint(0, 10000)
    b = rng.randint(0, 10000)
    low, high = min(a, b), max(a, b)
    return [out, low, high]

