class Solution:
    def trimBST(self, root, low, high):
        # independent: rebuild the surviving tree by walking the whole tree and
        # re-inserting each in-range value in pre-order into a fresh BST. Since the
        # source is a BST and pre-order insertion of a BST's nodes reproduces the
        # original shape, the trimmed result preserves relative structure.
        order = []
        def pre(node):
            if not node:
                return
            order.append(node.val)
            pre(node.left)
            pre(node.right)
        pre(root)
        new_root = None
        def insert(v):
            nonlocal new_root
            if new_root is None:
                new_root = TreeNode(v)
                return
            cur = new_root
            while True:
                if v < cur.val:
                    if cur.left is None:
                        cur.left = TreeNode(v); return
                    cur = cur.left
                else:
                    if cur.right is None:
                        cur.right = TreeNode(v); return
                    cur = cur.right
        for v in order:
            if low <= v <= high:
                insert(v)
        return new_root

